y $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.","label":"assert_on_manage_users_page($self,$name)"},"definition":"sub","detail":"($self,$name)","containerName":"main::","kind":12,"range":{"start":{"line":539,"character":0},"end":{"line":552,"character":9999}}},{"name":"context","kind":12,"line":542},{"name":"selector","kind":12,"line":546},{"line":546,"kind":12,"name":"text"},{"kind":12,"line":547,"name":"selector"},{"name":"match","line":547,"kind":12},{"name":"assert_on_new_record_page","children":[{"localvar":"my","kind":13,"definition":"my","containerName":"assert_on_new_record_page","name":"$self","line":561},{"containerName":"assert_on_new_record_page","name":"$name","kind":13,"line":561},{"containerName":"assert_on_new_record_page","name":"$name","line":562,"kind":13},{"localvar":"my","kind":13,"containerName":"assert_on_new_record_page","definition":"my","name":"$test","line":563},{"containerName":"assert_on_new_record_page","kind":13,"line":565,"name":"$self"},{"kind":12,"line":565,"name":"_assert_on_page","containerName":"assert_on_new_record_page"},{"containerName":"assert_on_new_record_page","line":566,"kind":13,"name":"$name"},{"name":"$test","kind":13,"line":571,"containerName":"assert_on_new_record_page"},{"containerName":"assert_on_new_record_page","line":571,"kind":12,"name":"release"},{"containerName":"assert_on_new_record_page","kind":13,"line":572,"name":"$self"}],"line":560,"range":{"start":{"line":560,"character":0},"end":{"line":573,"character":9999}},"kind":12,"signature":{"parameters":[{"label":"$self"},{"label":"$name"}],"documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.","label":"assert_on_new_record_page($self,$name)"},"definition":"sub","detail":"($self,$name)","containerName":"main::"},{"line":563,"kind":12,"name":"context"},{"line":568,"kind":12,"name":"selector"},{"line":568,"kind":12,"name":"text"},{"range":{"end":{"line":597,"character":9999},"start":{"character":0,"line":582}},"kind":12,"containerName":"main::","signature":{"parameters":[{"label":"$self"},{"label":"$name"},{"label":"$page_title"}],"documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.","label":"assert_on_see_records_page($self,$name,$page_title)"},"detail":"($self,$name,$page_title)","definition":"sub","name":"assert_on_see_records_page","children":[{"line":583,"name":"$self","containerName":"assert_on_see_records_page","definition":"my","kind":13,"localvar":"my"},{"containerName":"assert_on_see_records_page","line":583,"kind":13,"name":"$name"},{"containerName":"assert_on_see_records_page","line":583,"kind":13,"name":"$page_title"},{"line":584,"kind":13,"name":"$name","containerName":"assert_on_see_records_page"},{"containerName":"assert_on_see_records_page","name":"$page_title","line":585,"kind":13},{"name":"$title","line":586,"localvar":"my","kind":13,"containerName":"assert_on_see_records_page","definition":"my"},{"line":586,"kind":13,"name":"$page_title","containerName":"assert_on_see_records_page"},{"name":"$test","line":587,"localvar":"my","kind":13,"definition":"my","containerName":"assert_on_see_records_page"},{"containerName":"assert_on_see_records_page","name":"$self","kind":13,"line":589},{"containerName":"assert_on_see_records_page","name":"_assert_on_page","kind":12,"line":589},{"name":"$name","kind":13,"line":590,"containerName":"assert_on_see_records_page"},{"containerName":"assert_on_see_records_page","line":595,"kind":13,"