cords_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.","label":"assert_record_has_fields($self,$name,$expected_fields_ref)","parameters":[{"label":"$self"},{"label":"$name"},{"label":"$expected_fields_ref"}]},"definition":"sub","detail":"($self,$name,$expected_fields_ref)","range":{"end":{"character":9999,"line":655},"start":{"character":0,"line":628}},"kind":12,"children":[{"kind":13,"localvar":"my","definition":"my","containerName":"assert_record_has_fields","line":629,"name":"$self"},{"containerName":"assert_record_has_fields","line":629,"kind":13,"name":"$name"},{"containerName":"assert_record_has_fields","name":"$expected_fields_ref","line":629,"kind":13},{"containerName":"assert_record_has_fields","name":"$name","line":630,"kind":13},{"kind":13,"localvar":"my","containerName":"assert_record_has_fields","definition":"my","lin