ame":"_assert_on_page","kind":12,"line":764,"name":"diag"},{"name":"@failure","line":764,"kind":13,"containerName":"_assert_on_page"},{"containerName":"_assert_on_page","line":766,"kind":13,"name":"$test"},{"containerName":"_assert_on_page","name":"release","line":766,"kind":12},{"containerName":"_assert_on_page","name":"$self","line":767,"kind":13}],"line":742},{"name":"context","line":744,"kind":12},{"name":"selector","line":750,"kind":12},{"name":"dies","kind":12,"line":753},{"name":"tries","kind":12,"line":753},{"children":[{"kind":13,"localvar":"my","containerName":"_check_element_against_expectation","definition":"my","line":771,"name":"$self"},{"name":"$matching_el","kind":13,"line":771,"containerName":"_check_element_against_expectation"},{"line":771,"kind":13,"name":"$expect_ref","containerName":"_check_element_against_expectation"},{"localvar":"my","kind":13,"containerName":"_check_element_against_expectation","definition":"my","name":"$matching_text","line":772},{"name":"$matching_el","line":772,"kind":13,"containerName":"_check_element_against_expectation"},{"containerName":"_check_element_against_expectation","kind":12,"line":772,"name":"text"},{"kind":13,"localvar":"my","definition":"my","containerName":"_check_element_against_expectation","line":773,"name":"%expect"},{"line":773,"kind":13,"name":"$expect_ref","containerName":"_check_element_against_expectation"},{"kind":13,"localvar":"my","containerName":"_check_element_against_expectation","definition":"my","line":775,"name":"@failure"},{"name":"$expect","line":776,"kind":13,"containerName":"_check_element_against_expectation"},{"name":"$expect","kind":13,"line":776,"containerName":"_check_element_against_expectation"},{"name":"@failure","kind":13,"line":777,"containerName":"_check_element_against_expectation"},{"containerName":"_check_element_against_expectation","line":779,"kind":13,"name":"$expect"},{"name":"$matching_text","line":780,"kind":13,"containerName":"_check_element_against_expectation"},{"containerName":"_check_element_against_expectation","name":"$expect","kind":13,"line":780},{"containerName":"_check_element_against_expectation","name":"@failure","kind":13,"line":781},{"containerName":"_check_element_against_expectation","name":"$expect","line":784,"kind":13},{"name":"$matching_text","kind":13,"line":785,"containerName":"_check_element_against_expectation"},{"containerName":"_check_element_against_expectation","kind":13,"line":786,"name":"@failure"},{"kind":13,"line":790,"name":"@failure","containerName":"_check_element_against_expectation"},{"containerName":"_check_element_against_expectation","kind":13,"line":793,"name":"@failure"}],"name":"_check_element_against_expectation","line":770,"signature":{"parameters":[{"label":"$self"},{"label":"$matching_el"},{"label":"$expect_ref"}],"documentation":"","label":"_check_element_against_expectation($self,$matching_el,$expect_ref)"},"definition":"sub","detail":"($self,$matching_el,$expect_ref)","containerName":"main::","range":{"start":{"line":770,"character":0},"end":{"character":9999,"line":794}},"kind":12},{"kind":12,"line":776,"name":"text"},{"line":776,"kind":12,"name":"match"},{"name":"text","kind":12,"line":779},{"line":780,"kind":12,"name":"text"},{"line":784,"kind":12,"name":"match"},{"kind":12,"range":{"start":{"line":806,"character":0},"end":{"character":9999,"line":834}},"definition":"sub","signature":{"documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.","label":"assign_current_user_to_group_ok($self,$name,$group_name)","parameters":[{"label":"$self"},{"label":"$name"},{"label":"$group_name"}]},"detail":"($self,$name,$group_name)","containerName":"main::","line":806,"children":[{"kind":13,"localvar":"my","containerName":"assign_current_user_to_group_ok","definition":"my","line":807,"name":"$self"},{"line":807,"kind":13,"name":"$name","containerName":"assign_current_user_to_group_ok"},{"kind":13,"line":807,"name":"$group_name","containerName":"assign_current_user_to_group_ok"},{"containerName":"assign_current_user_to_group_ok","definition":"my","localvar":"my","kind":13,"name":"$test","line":808},{"line":809,"name":"$webdriver","containerName":"assign_current_user_to_group_ok","definition":"my","kind":13,"localvar":"my"},{"containerName":"assign_current_user_to_group_ok","name":"$self","kind":13,"line":809},{"containerName":"assign_current_user_to_group_ok","line":809,"kind":12,"name":"gads"},{"containerName":"assign_current_user_to_group_ok","name":"webdriver","line":809,"kind":12},{"line":811,"name":"$query","containerName":"assign_current_user_to_group_ok","definition":"my","kind":13,"localvar":"my"},{"line":815,"name":"$checkbox_el","definition":"my","containerName":"assign_current_user_to_group_ok","kind":13,"localvar":"my"},{"containerName":"assign_current_user_to_group_ok","name":"$webdriver","kind":13,"line":815},{"name":"find","kind":12,"line":815,"containerName":"assign_current_user_to_group_ok"},{"containerName":"assign_current_user_to_group_ok","name":"$query","line":815,"kind":13},{"definition":"my","containerName":"assign_current_user_to_group_ok","kind":13,"localvar":"my","line":818,"name":"$description"},{"line":819,"name":"$success","containerName":"assign_current_user_to_group_ok","definition":"my","kind":13,"localvar":"my"},{"line":819,"kind":13,"name":"$self","containerName":"assign_current_user_to_group_ok"},{"name":"_check_only_one","line":819,"kind":12,"containerName":"assign_current_user_to_group_ok"},{"kind":13,"line":819,"name":"$checkbox_el","containerName":"assign_current_user_to_group_ok"},{"containerName":"assign_current_user_to_group_ok","kind":13,"line":819,"name":"$description"},{"containerName":"assign_current_user_to_group_ok","name":"$checkbox_el","line":820,"kind":13},{"kind":12,"line":820,"name":"selected","containerName":"assign_current_user_to_group_ok"},{"kind":13,"line":821,"name":"$success","containerName":"assign_current_user_to_group_ok"},{"containerName":"assign_current_user_to_group_ok","name":"$test","line":822,"kind":13},{"containerName":"assign_current_user_to_group_ok","name":"diag","line":822,"kind":12},{"name":"$checkbox_el","line":824,"kind":13,"containerName":"assign_current_user_to_group_ok"},{"line":824,"kind":12,"name":"find","containerName":"assign_current_user_to_group_ok"},{"containerName":"assign_current_user_to_group_ok","name":"click","line":824,"kind":12},{"containerName":"assign_current_user_to_group_ok","definition":"my","kind":13,"localvar":"my","line":826,"name":"$group_id"},{"kind":13,"line":826,"name":"$checkbox_el","containerName":"assign_current_user_to_group_ok"},{"containerName":"assign_current_user_to_group_ok","line":826,"kind":12,"name":"attr"},{"containerName":"assign_current_user_to_group_ok","kind":13,"line":827,"name":"$webdriver"},{"containerName":"assign_current_user_to_group_ok","line":827,"kind":12,"name":"find"},{"containerName":"assign_current_user_to_group_ok","name":"$success","kind":13,"line":828},{"containerName":"assign_current_user_to_group_ok","line":828,"kind":13,"name":"$self"},{"containerName":"assign_current_user_to_group_ok","kind":12,"line":828,"name":"_click_submit_button"},{"containerName":"assign_current_user_to_group_ok","name":"$test","kind":13,"line":830},{"containerName":"assign_current_user_to_group_ok","name":"ok","line":830,"kind":12},{"line":830,"kind":13,"name":"$success","containerName":"assign_current_user_to_group_ok"},{"name":"$name","kind":13,"line":830,"containerName":"assign_current_user_to_group_ok"},{"line":832,"kind":13,"name":"$test","containerName":"assign_current_user_to_group_ok"},{"containerName":"assign_current_user_to_group_ok","name":"release","kind":12,"line":832},{"name":"$self","line":833,"kind":13,"containerName":"assign_current_user_to_group_ok"}],"name":"assign_current_user_to_group_ok"},{"name":"context","line":808,"kind":12},{"name":"method","line":816,"kind":12},{"name":"dies","kind":12,"line":816},{"name":"tries","line":816,"kind":12},{"name":"method","line":824,"kind":12},{"line":844,"children":[{"definition":"my","containerName":"confirm_deletion_ok","kind":13,"localvar":"my","line":845,"name":"$self"},{"name":"$name","kind":13,"line":845,"containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","line":846,"kind":13,"name":"$name"},{"definition":"my","containerName":"confirm_deletion_ok","kind":13,"localvar":"my","line":847,"name":"$test"},{"kind":13,"localvar":"my","containerName":"confirm_deletion_ok","definition":"my","line":848,"name":"$webdriver"},{"name":"$self","kind":13,"line":848,"containerName":"confirm_deletion_ok"},{"name":"gads","kind":12,"line":848,"containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","name":"webdriver","line":848,"kind":12},{"line":850,"name":"$entity_name","containerName":"confirm_deletion_ok","definition":"my","kind":13,"localvar":"my"},{"containerName":"confirm_deletion_ok","name":"$webdriver","line":850,"kind":13},{"name":"find","line":850,"kind":12,"containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","name":"attr","line":853,"kind":12},{"name":"$delete_button_el","line":855,"containerName":"confirm_deletion_ok","definition":"my","localvar":"my","kind":13},{"containerName":"confirm_deletion_ok","name":"$webdriver","kind":13,"line":855},{"kind":12,"line":855,"name":"find","containerName":"confirm_deletion_ok"},{"line":860,"name":"$success","containerName":"confirm_deletion_ok","definition":"my","kind":13,"localvar":"my"},{"containerName":"confirm_deletion_ok","name":"$self","line":860,"kind":13},{"name":"_check_only_one","kind":12,"line":860,"containerName":"confirm_deletion_ok"},{"line":860,"kind":13,"name":"$delete_button_el","containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","line":861,"kind":13,"name":"$success"},{"kind":13,"line":862,"name":"$delete_button_el","containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","line":862,"kind":12,"name":"click"},{"kind":13,"localvar":"my","containerName":"confirm_deletion_ok","definition":"my","line":864,"name":"$selector"},{"name":"$confirm_button_el","line":865,"containerName":"confirm_deletion_ok","definition":"my","localvar":"my","kind":13},{"name":"$webdriver","kind":13,"line":865,"containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","name":"find","line":865,"kind":12},{"containerName":"confirm_deletion_ok","name":"$selector","line":865,"kind":13},{"line":867,"kind":13,"name":"$confirm_button_el","containerName":"confirm_deletion_ok"},{"name":"size","line":867,"kind":12,"containerName":"confirm_deletion_ok"},{"kind":13,"line":868,"name":"$test","containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","kind":12,"line":868,"name":"note"},{"name":"$confirm_button_el","line":869,"kind":13,"containerName":"confirm_deletion_ok"},{"name":"click","kind":12,"line":869,"containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","kind":13,"line":872,"name":"$success"},{"containerName":"confirm_deletion_ok","name":"$test","line":873,"kind":13},{"containerName":"confirm_deletion_ok","name":"diag","kind":12,"line":873},{"containerName":"confirm_deletion_ok","kind":13,"line":876,"name":"$test"},{"line":876,"kind":12,"name":"ok","containerName":"confirm_deletion_ok"},{"containerName":"confirm_deletion_ok","name":"$success","line":876,"kind":13},{"containerName":"confirm_deletion_ok","name":"$name","kind":13,"line":876},{"containerName":"confirm_deletion_ok","kind":13,"line":878,"name":"$test"},{"line":878,"kind":12,"name":"release","containerName":"confirm_deletion_ok"},{"kind":13,"line":879,"name":"$self","containerName":"confirm_deletion_ok"}],"name":"confirm_deletion_ok","containerName":"main::","definition":"sub","signature":{"parameters":[{"label":"$self"},{"label":"$name"}],"documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.","label":"confirm_deletion_ok($self,$name)"},"detail":"($self,$name)","kind":12,"range":{"start":{"line":844,"character":0},"end":{"character":9999,"line":880}}},{"line":847,"kind":12,"name":"context"},{"name":"tries","kind":12,"line":852},{"name":"dies","line":857,"kind":12},{"name":"dies","line":865,"kind":12},{"children":[{"line":890,"name":"$self","containerName":"delete_current_view_ok","definition":"my","kind":13,"localvar":"my"},{"containerName":"delete_current_view_ok","line":890,"kind":13,"name":"$name"},{"containerName":"delete_current_view_ok","name":"$name","line":891,"kind":13},{"name":"$test","line":892,"localvar":"my","kind":13,"containerName":"delete_current_view_ok","definition":"my"},{"containerName":"delete_current_view_ok","definition":"my","kind":13,"localvar":"my","line":893,"name":"$webdriver"},{"name":"$self","kind":13,"line":893,"containerName":"delete_current_view_ok"},{"name":"gads","line":893,"kind":12,"containerName":"delete_current_view_ok"},{"containerName":"delete_current_view_ok","name":"webdriver","line":893,"kind":12},{"name":"$view_name","line":895,"localvar":"my","kind":13,"definition":"my","containerName":"delete_current_view_ok"},{"name":"$webdriver","kind":13,"line":895,"containerName":"delete_current_view_ok"},{"containerName":"delete_current_view_ok","name":"find","kind":12,"line":895},{"containerName":"delete_current_view_ok","line":895,"kind":12,"name":"attr"},{"name":"$webdriver","kind":13,"line":900,"containerName":"delete_current_view_ok"},{"containerName":"delete_current_view_ok","line":900,"kind":12,"name":"js"},{"name":"@failure","line":902,"localvar":"my","kind":13,"containerName":"delete_current_view_ok","definition":"my"},{"name":"$self","kind":13,"line":902,"containerName":"delete_current_view_ok"},{"name":"_find_and_click","line":902,"kind":12,"containerName":"delete_current_view_ok"},{"line":904,"kind":13,"name":"$test","containerName":"delete_current_view_ok"},{"containerName":"delete_current_view_ok","line":904,"kind":12,"name":"note"},{"name":"$webdriver","line":905,"kind":13,"containerName":"delete_current_view_ok"},{"line":905,"kind":12,"name":"find","containerName":"delete_current_view_ok"},{"containerName":"delete_current_view_ok","line":905,"kind":12,"name":"click"},{"containerName":"delete_current_view_ok","name":"$test","line":907,"kind":13},{"containerName":"delete_current_view_ok","kind":12,"line":907,"name":"ok"},{"line":907,"kind":13,"name":"@failure","containerName":"delete_current_view_ok"},{"name":"$name","kind":13,"line":907,"containerName":"delete_current_view_ok"},{"containerName":"delete_current_view_ok","line":908,"kind":13,"name":"$test"},{"line":908,"kind":12,"name":"diag","containerName":"delete_current_view_ok"},{"containerName":"delete_current_view_ok","line":908,"kind":13,"name":"@failure"},{"line":910,"kind":13,"name":"$test","containerName":"delete_current_view_ok"},{"containerName":"delete_current_view_ok","name":"release","kind":12,"line":910},{"containerName":"delete_current_view_ok","name":"$self","line":912,"kind":13}],"name":"delete_current_view_ok","line":889,"range":{"end":{"character":9999,"line":912},"start":{"line":889,"character":0}},"kind":12,"detail":"($self,$name)","signature":{"label":"delete_current_view_ok($self,$name)","documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n Very similar to delete_viewed_record_ok()","parameters":[{"label":"$self"},{"label":"$name"}]},"definition":"sub","containerName":"main::"},{"name":"context","line":892,"kind":12},{"name":"delete_viewed_record_ok","children":[{"containerName":"delete_viewed_record_ok","definition":"my","kind":13,"localvar":"my","line":922,"name":"$self"},{"containerName":"delete_viewed_record_ok","name":"$name","line":922,"kind":13},{"name":"$name","line":923,"kind":13,"containerName":"delete_viewed_record_ok"},{"localvar":"my","kind":13,"containerName":"delete_viewed_record_ok","definition":"my","name":"$test","line":924},{"containerName":"delete_viewed_record_ok","definition":"my","kind":13,"localvar":"my","line":925,"name":"$webdriver"},{"containerName":"delete_viewed_record_ok","line":925,"kind":13,"name":"$self"},{"containerName":"delete_viewed_record_ok","name":"gads","kind":12,"line":925},{"containerName":"delete_viewed_record_ok","name":"webdriver","line":925,"kind":12},{"line":926,"name":"$record_title","containerName":"delete_viewed_record_ok","definition":"my","kind":13,"localvar":"my"},{"containerName":"delete_viewed_record_ok","name":"$webdriver","kind":13,"line":926},{"containerName":"delete_viewed_record_ok","name":"find","line":926,"kind":12},{"containerName":"delete_viewed_record_ok","name":"text","kind":12,"line":926},{"containerName":"delete_viewed_record_ok","kind":13,"line":931,"name":"$webdriver"},{"containerName":"delete_viewed_record_ok","kind":12,"line":931,"name":"js"},{"containerName":"delete_viewed_record_ok","definition":"my","localvar":"my","kind":13,"name":"@failure","line":933},{"containerName":"delete_viewed_record_ok","name":"$self","kind":13,"line":933},{"containerName":"delete_viewed_record_ok","name":"_find_and_click","kind":12,"line":933},{"name":"$test","line":935,"kind":13,"containerName":"delete_viewed_record_ok"},{"containerName":"delete_viewed_record_ok","kind":12,"line":935,"name":"note"},{"name":"$webdriver","line":936,"kind":13,"containerName":"delete_viewed_record_ok"},{"line":936,"kind":12,"name":"find","containerName":"delete_viewed_record_ok"},{"kind":12,"line":936,"name":"click","containerName":"delete_viewed_record_ok"},{"containerName":"delete_viewed_record_ok","kind":13,"line":938,"name":"$test"},{"kind":12,"line":938,"name":"ok","containerName":"delete_viewed_record_ok"},{"containerName":"delete_viewed_record_ok","name":"@failure","kind":13,"line":938},{"containerName":"delete_viewed_record_ok","name":"$name","line":938,"kind":13},{"containerName":"delete_viewed_record_ok","line":939,"kind":13,"name":"$test"},{"containerName":"delete_viewed_record_ok","line":939,"kind":12,"name":"diag"},{"name":"@failure","kind":13,"line":939,"containerName":"delete_viewed_record_ok"},{"line":941,"kind":13,"name":"$test","containerName":"delete_viewed_record_ok"},{"name":"release","kind":12,"line":941,"containerName":"delete_viewed_record_ok"},{"kind":13,"line":943,"name":"$self","containerName":"delete_viewed_record_ok"}],"line":921,"containerName":"main::","detail":"($self,$name)","signature":{"parameters":[{"label":"$self"},{"label":"$name"}],"documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n Very similar to delete_current_view_ok()","label":"delete_viewed_record_ok($self,$name)"},"definition":"sub","range":{"start":{"line":921,"character":0},"end":{"line":943,"character":9999}},"kind":12},{"kind":12,"line":924,"name":"context"},{"name":"jquery","line":933,"kind":12},{"containerName":"main::","definition":"sub","signature":{"parameters":[{"label":"$self"},{"label":"$name"},{"label":"$link_text"}],"label":"follow_link_ok($self,$name,$link_text)","documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n\n# Very similar to delete_current_view_ok()\nsub delete_viewed_record_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently viewed record';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n    my $record_title = $webdriver->find('h2')->text;\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ '.btn-delete' ], jquery => 1 );\n\n    $test->note(\"About to delete $record_title\");\n    $webdriver->find('#modaldelete .btn-primary.submit_button')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 follow_link_ok\n\nTakes a string and follows a link containing that string's text."},"detail":"($self,$name,$link_text)","kind":12,"range":{"start":{"character":0,"line":951},"end":{"line":971,"character":9999}},"line":951,"name":"follow_link_ok","children":[{"line":952,"name":"$self","definition":"my","containerName":"follow_link_ok","kind":13,"localvar":"my"},{"line":952,"kind":13,"name":"$name","containerName":"follow_link_ok"},{"containerName":"follow_link_ok","kind":13,"line":952,"name":"$link_text"},{"containerName":"follow_link_ok","name":"$name","kind":13,"line":953},{"name":"$test","line":954,"localvar":"my","kind":13,"containerName":"follow_link_ok","definition":"my"},{"definition":"my","containerName":"follow_link_ok","kind":13,"localvar":"my","line":955,"name":"$webdriver"},{"name":"$self","kind":13,"line":955,"containerName":"follow_link_ok"},{"containerName":"follow_link_ok","line":955,"kind":12,"name":"gads"},{"containerName":"follow_link_ok","name":"webdriver","kind":12,"line":955},{"containerName":"follow_link_ok","definition":"my","localvar":"my","kind":13,"name":"$link_el","line":957},{"kind":13,"line":957,"name":"$webdriver","containerName":"follow_link_ok"},{"containerName":"follow_link_ok","kind":12,"line":957,"name":"find"},{"name":"$success","line":964,"localvar":"my","kind":13,"definition":"my","containerName":"follow_link_ok"},{"line":964,"kind":13,"name":"$self","containerName":"follow_link_ok"},{"name":"_check_only_one","kind":12,"line":964,"containerName":"follow_link_ok"},{"containerName":"follow_link_ok","kind":13,"line":965,"name":"$link_el"},{"name":"$link_el","line":966,"kind":13,"containerName":"follow_link_ok"},{"kind":12,"line":966,"name":"click","containerName":"follow_link_ok"},{"line":966,"kind":13,"name":"$success","containerName":"follow_link_ok"},{"containerName":"follow_link_ok","definition":"my","kind":13,"localvar":"my","line":968,"name":"$result"},{"containerName":"follow_link_ok","kind":13,"line":968,"name":"$test"},{"containerName":"follow_link_ok","name":"ok","kind":12,"line":968},{"containerName":"follow_link_ok","line":968,"kind":13,"name":"$success"},{"line":968,"kind":13,"name":"$name","containerName":"follow_link_ok"},{"containerName":"follow_link_ok","name":"$test","line":969,"kind":13},{"containerName":"follow_link_ok","name":"release","kind":12,"line":969},{"kind":13,"line":970,"name":"$result","containerName":"follow_link_ok"}]},{"kind":12,"line":954,"name":"context"},{"name":"method","kind":12,"line":960},{"kind":12,"line":961,"name":"dies"},{"kind":12,"range":{"start":{"character":0,"line":979},"end":{"line":991,"character":9999}},"containerName":"main::","detail":"($self,$name,$selectors_ref)","signature":{"parameters":[{"label":"$self"},{"label":"$name"},{"label":"$selectors_ref"}],"documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n\n# Very similar to delete_current_view_ok()\nsub delete_viewed_record_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently viewed record';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n    my $record_title = $webdriver->find('h2')->text;\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ '.btn-delete' ], jquery => 1 );\n\n    $test->note(\"About to delete $record_title\");\n    $webdriver->find('#modaldelete .btn-primary.submit_button')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 follow_link_ok\n\nTakes a string and follows a link containing that string's text.\n\n\nsub follow_link_ok {\n    my ( $self, $name, $link_text ) = @_;\n    $name //= \"Follow the link containing '${link_text}'\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $link_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//main//a[ contains( ., '${link_text}') ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one(\n        $link_el, \"link containing '${link_text}'\"); ;\n    $link_el->click if $success;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 navigate_ok\n\nTakes an array reference of selectors to click on in the site navigation.","label":"navigate_ok($self,$name,$selectors_ref)"},"definition":"sub","line":979,"name":"navigate_ok","children":[{"line":980,"name":"$self","definition":"my","containerName":"navigate_ok","kind":13,"localvar":"my"},{"containerName":"navigate_ok","name":"$name","line":980,"kind":13},{"containerName":"navigate_ok","name":"$selectors_ref","line":980,"kind":13},{"name":"$name","kind":13,"line":981,"containerName":"navigate_ok"},{"containerName":"navigate_ok","name":"$selectors_ref","kind":13,"line":981},{"name":"$test","line":982,"localvar":"my","kind":13,"definition":"my","containerName":"navigate_ok"},{"line":983,"name":"$webdriver","containerName":"navigate_ok","definition":"my","kind":13,"localvar":"my"},{"containerName":"navigate_ok","kind":13,"line":983,"name":"$self"},{"containerName":"navigate_ok","name":"gads","line":983,"kind":12},{"name":"webdriver","line":983,"kind":12,"containerName":"navigate_ok"},{"kind":13,"localvar":"my","definition":"my","containerName":"navigate_ok","line":985,"name":"@failure"},{"line":985,"kind":13,"name":"$self","containerName":"navigate_ok"},{"kind":12,"line":985,"name":"_find_and_click","containerName":"navigate_ok"},{"containerName":"navigate_ok","line":985,"kind":13,"name":"$selectors_ref"},{"containerName":"navigate_ok","name":"$test","line":986,"kind":13},{"name":"ok","line":986,"kind":12,"containerName":"navigate_ok"},{"kind":13,"line":986,"name":"@failure","containerName":"navigate_ok"},{"containerName":"navigate_ok","name":"$name","line":986,"kind":13},{"containerName":"navigate_ok","name":"$test","line":987,"kind":13},{"kind":12,"line":987,"name":"diag","containerName":"navigate_ok"},{"name":"@failure","line":987,"kind":13,"containerName":"navigate_ok"},{"containerName":"navigate_ok","kind":13,"line":989,"name":"$test"},{"containerName":"navigate_ok","name":"release","kind":12,"line":989},{"containerName":"navigate_ok","name":"$self","kind":13,"line":990}]},{"kind":12,"line":982,"name":"context"},{"name":"_find_and_click","children":[{"kind":13,"localvar":"my","containerName":"_find_and_click","definition":"my","line":994,"name":"$self"},{"line":994,"kind":13,"name":"$selectors_ref","containerName":"_find_and_click"},{"name":"%arg","line":994,"kind":13,"containerName":"_find_and_click"},{"line":995,"name":"$webdriver","definition":"my","containerName":"_find_and_click","kind":13,"localvar":"my"},{"name":"$self","line":995,"kind":13,"containerName":"_find_and_click"},{"kind":12,"line":995,"name":"gads","containerName":"_find_and_click"},{"containerName":"_find_and_click","name":"webdriver","line":995,"kind":12},{"line":997,"name":"@failure","definition":"my","containerName":"_find_and_click","kind":13,"localvar":"my"},{"kind":13,"localvar":"my","containerName":"_find_and_click","definition":"my","line":998,"name":"$selector"},{"containerName":"_find_and_click","name":"$selectors_ref","kind":13,"line":998},{"name":"$found_el","line":1000,"localvar":"my","kind":13,"definition":"my","containerName":"_find_and_click"},{"containerName":"_find_and_click","name":"$webdriver","line":1000,"kind":13},{"containerName":"_find_and_click","name":"find","kind":12,"line":1000},{"containerName":"_find_and_click","name":"$selector","kind":13,"line":1000},{"kind":13,"line":1001,"name":"$found_el","containerName":"_find_and_click"},{"line":1001,"kind":12,"name":"size","containerName":"_find_and_click"},{"containerName":"_find_and_click","line":1002,"kind":13,"name":"@failure"},{"containerName":"_find_and_click","line":1004,"kind":13,"name":"$found_el"},{"containerName":"_find_and_click","kind":12,"line":1004,"name":"visible"},{"name":"@failure","line":1005,"kind":13,"containerName":"_find_and_click"},{"containerName":"_find_and_click","kind":13,"line":1010,"name":"$arg"},{"line":1010,"kind":13,"name":"$arg","containerName":"_find_and_click"},{"containerName":"_find_and_click","kind":13,"line":1011,"name":"$webdriver"},{"containerName":"_find_and_click","name":"js","line":1011,"kind":12},{"name":"$found_el","line":1014,"kind":13,"containerName":"_find_and_click"},{"name":"click","kind":12,"line":1014,"containerName":"_find_and_click"},{"name":"@failure","line":1019,"kind":13,"containerName":"_find_and_click"}],"line":993,"definition":"sub","signature":{"label":"_find_and_click($self,$selectors_ref,%arg)","documentation":"","parameters":[{"label":"$self"},{"label":"$selectors_ref"},{"label":"%arg"}]},"detail":"($self,$selectors_ref,%arg)","containerName":"main::","range":{"end":{"character":9999,"line":1020},"start":{"line":993,"character":0}},"kind":12},{"kind":12,"line":1000,"name":"dies"},{"kind":12,"line":1000,"name":"tries"},{"name":"jquery","kind":12,"line":1010},{"line":1010,"kind":12,"name":"jquery"},{"name":"purge_deleted_records_ok","children":[{"definition":"my","containerName":"purge_deleted_records_ok","localvar":"my","kind":13,"name":"$self","line":1029},{"name":"$name","line":1029,"kind":13,"containerName":"purge_deleted_records_ok"},{"name":"$name","kind":13,"line":1030,"containerName":"purge_deleted_records_ok"},{"line":1031,"name":"$test","kind":13,"localvar":"my","definition":"my","containerName":"purge_deleted_records_ok"},{"line":1032,"name":"$webdriver","kind":13,"localvar":"my","containerName":"purge_deleted_records_ok","definition":"my"},{"containerName":"purge_deleted_records_ok","kind":13,"line":1032,"name":"$self"},{"containerName":"purge_deleted_records_ok","name":"gads","line":1032,"kind":12},{"containerName":"purge_deleted_records_ok","name":"webdriver","kind":12,"line":1032},{"name":"$test","line":1034,"kind":13,"containerName":"purge_deleted_records_ok"},{"name":"note","line":1034,"kind":12,"containerName":"purge_deleted_records_ok"},{"name":"@failure","line":1035,"localvar":"my","kind":13,"containerName":"purge_deleted_records_ok","definition":"my"},{"name":"$self","line":1035,"kind":13,"containerName":"purge_deleted_records_ok"},{"containerName":"purge_deleted_records_ok","name":"_find_and_click","line":1035,"kind":12},{"containerName":"purge_deleted_records_ok","definition":"my","kind":13,"localvar":"my","line":1036,"name":"$title_el"},{"containerName":"purge_deleted_records_ok","line":1036,"kind":13,"name":"$webdriver"},{"containerName":"purge_deleted_records_ok","kind":12,"line":1036,"name":"find"},{"containerName":"purge_deleted_records_ok","line":1037,"kind":13,"name":"@failure"},{"containerName":"purge_deleted_records_ok","kind":13,"line":1037,"name":"$self"},{"containerName":"purge_deleted_records_ok","line":1037,"kind":12,"name":"_check_element_against_expectation"},{"containerName":"purge_deleted_records_ok","name":"$title_el","kind":13,"line":1038},{"containerName":"purge_deleted_records_ok","name":"$webdriver","kind":13,"line":1043},{"line":1043,"kind":12,"name":"js","containerName":"purge_deleted_records_ok"},{"containerName":"purge_deleted_records_ok","line":1045,"kind":13,"name":"@failure"},{"containerName":"purge_deleted_records_ok","line":1045,"kind":13,"name":"$self"},{"containerName":"purge_deleted_records_ok","name":"_find_and_click","kind":12,"line":1045},{"name":"$webdriver","line":1049,"kind":13,"containerName":"purge_deleted_records_ok"},{"line":1049,"kind":12,"name":"find","containerName":"purge_deleted_records_ok"},{"kind":12,"line":1049,"name":"click","containerName":"purge_deleted_records_ok"},{"containerName":"purge_deleted_records_ok","line":1051,"kind":13,"name":"$test"},{"containerName":"purge_deleted_records_ok","line":1051,"kind":12,"name":"ok"},{"containerName":"purge_deleted_records_ok","kind":13,"line":1051,"name":"@failure"},{"containerName":"purge_deleted_records_ok","line":1051,"kind":13,"name":"$name"},{"name":"$test","kind":13,"line":1052,"containerName":"purge_deleted_records_ok"},{"containerName":"purge_deleted_records_ok","kind":12,"line":1052,"name":"diag"},{"kind":13,"line":1052,"name":"@failure","containerName":"purge_deleted_records_ok"},{"containerName":"purge_deleted_records_ok","name":"$test","line":1053,"kind":13},{"containerName":"purge_deleted_records_ok","line":1053,"kind":12,"name":"release"},{"containerName":"purge_deleted_records_ok","name":"$self","kind":13,"line":1055}],"line":1028,"containerName":"main::","signature":{"parameters":[{"label":"$self"},{"label":"$name"}],"label":"purge_deleted_records_ok($self,$name)","documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n\n# Very similar to delete_current_view_ok()\nsub delete_viewed_record_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently viewed record';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n    my $record_title = $webdriver->find('h2')->text;\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ '.btn-delete' ], jquery => 1 );\n\n    $test->note(\"About to delete $record_title\");\n    $webdriver->find('#modaldelete .btn-primary.submit_button')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 follow_link_ok\n\nTakes a string and follows a link containing that string's text.\n\n\nsub follow_link_ok {\n    my ( $self, $name, $link_text ) = @_;\n    $name //= \"Follow the link containing '${link_text}'\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $link_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//main//a[ contains( ., '${link_text}') ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one(\n        $link_el, \"link containing '${link_text}'\"); ;\n    $link_el->click if $success;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 navigate_ok\n\nTakes an array reference of selectors to click on in the site navigation.\n\n\nsub navigate_ok {\n    my ( $self, $name, $selectors_ref ) = @_;\n    $name //= \"Navigate to \" . join \" \", @$selectors_ref;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure = $self->_find_and_click($selectors_ref);\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _find_and_click {\n    my ( $self, $selectors_ref, %arg ) = @_;\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $selector (@$selectors_ref) {\n        # TODO: Move 'tries' to configuration\n        my $found_el = $webdriver->find( $selector, dies => 0, tries => 25 );\n        if ( 0 == $found_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( !$found_el->visible ) {\n            push @failure, \"No visible elements matching '${selector}' found\";\n        }\n        else {\n            # TODO: Avoid using a special approach for when jQuery and\n            # WebDriver handle clicks differently\n            if ( exists $arg{jquery} and $arg{jquery} ) {\n                $webdriver->js( qq[ \\$(\"${selector}\").click() ]);\n            }\n            else {\n                $found_el->click;\n            }\n        }\n    }\n\n    return @failure;\n}\n\n=head3 purge_deleted_records_ok\n\nPurge all deleted records from the current table."},"definition":"sub","detail":"($self,$name)","range":{"end":{"line":1056,"character":9999},"start":{"character":0,"line":1028}},"kind":12},{"line":1031,"kind":12,"name":"context"},{"kind":12,"line":1036,"name":"dies"},{"line":1036,"kind":12,"name":"tries"},{"line":1038,"kind":12,"name":"text"},{"line":1064,"children":[{"line":1065,"name":"$self","definition":"my","containerName":"select_current_user_to_edit_ok","kind":13,"localvar":"my"},{"containerName":"select_current_user_to_edit_ok","name":"$name","kind":13,"line":1065},{"name":"$test","line":1066,"definition":"my","containerName":"select_current_user_to_edit_ok","localvar":"my","kind":13},{"name":"$result","line":1068,"containerName":"select_current_user_to_edit_ok","definition":"my","localvar":"my","kind":13},{"name":"$self","kind":13,"line":1068,"containerName":"select_current_user_to_edit_ok"},{"containerName":"select_current_user_to_edit_ok","name":"_select_item_row_to_edit_ok","kind":12,"line":1068},{"line":1069,"kind":13,"name":"$name","containerName":"select_current_user_to_edit_ok"},{"kind":13,"line":1069,"name":"$self","containerName":"select_current_user_to_edit_ok"},{"containerName":"select_current_user_to_edit_ok","name":"gads","line":1069,"kind":12},{"containerName":"select_current_user_to_edit_ok","name":"username","kind":12,"line":1069},{"containerName":"select_current_user_to_edit_ok","line":1071,"kind":13,"name":"$test"},{"containerName":"select_current_user_to_edit_ok","name":"release","line":1071,"kind":12},{"name":"$result","line":1072,"kind":13,"containerName":"select_current_user_to_edit_ok"}],"name":"select_current_user_to_edit_ok","detail":"($self,$name)","signature":{"label":"select_current_user_to_edit_ok($self,$name)","documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n\n# Very similar to delete_current_view_ok()\nsub delete_viewed_record_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently viewed record';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n    my $record_title = $webdriver->find('h2')->text;\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ '.btn-delete' ], jquery => 1 );\n\n    $test->note(\"About to delete $record_title\");\n    $webdriver->find('#modaldelete .btn-primary.submit_button')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 follow_link_ok\n\nTakes a string and follows a link containing that string's text.\n\n\nsub follow_link_ok {\n    my ( $self, $name, $link_text ) = @_;\n    $name //= \"Follow the link containing '${link_text}'\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $link_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//main//a[ contains( ., '${link_text}') ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one(\n        $link_el, \"link containing '${link_text}'\"); ;\n    $link_el->click if $success;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 navigate_ok\n\nTakes an array reference of selectors to click on in the site navigation.\n\n\nsub navigate_ok {\n    my ( $self, $name, $selectors_ref ) = @_;\n    $name //= \"Navigate to \" . join \" \", @$selectors_ref;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure = $self->_find_and_click($selectors_ref);\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _find_and_click {\n    my ( $self, $selectors_ref, %arg ) = @_;\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $selector (@$selectors_ref) {\n        # TODO: Move 'tries' to configuration\n        my $found_el = $webdriver->find( $selector, dies => 0, tries => 25 );\n        if ( 0 == $found_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( !$found_el->visible ) {\n            push @failure, \"No visible elements matching '${selector}' found\";\n        }\n        else {\n            # TODO: Avoid using a special approach for when jQuery and\n            # WebDriver handle clicks differently\n            if ( exists $arg{jquery} and $arg{jquery} ) {\n                $webdriver->js( qq[ \\$(\"${selector}\").click() ]);\n            }\n            else {\n                $found_el->click;\n            }\n        }\n    }\n\n    return @failure;\n}\n\n=head3 purge_deleted_records_ok\n\nPurge all deleted records from the current table.\n\n\nsub purge_deleted_records_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Purge all deleted records from the current table';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    $test->note('About to purge the deleted records');\n    my @failure = $self->_find_and_click( [ \"#admin-menu\", \".manage-deleted\" ] );\n    my $title_el = $webdriver->find( 'h2', dies => 0, tries => 10 );\n    push @failure, $self->_check_element_against_expectation(\n        $title_el, { text => 'Manage deleted records' } );\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    push @failure, $self->_find_and_click([\n        '#selectall',\n        'button[data-target=\"#purge\"]',\n    ]);\n    $webdriver->find('button[type=\"submit\"][name=\"purge\"]')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n    $test->release;\n\n    return $self;\n}\n\n=head3 select_current_user_to_edit_ok\n\nFrom the I<< Manage users >> page, select the currently logged in user.","parameters":[{"label":"$self"},{"label":"$name"}]},"definition":"sub","containerName":"main::","kind":12,"range":{"start":{"character":0,"line":1064},"end":{"character":9999,"line":1073}}},{"line":1066,"kind":12,"name":"context"},{"range":{"end":{"character":9999,"line":1089},"start":{"character":0,"line":1081}},"kind":12,"definition":"sub","containerName":"main::","name":"select_field_to_edit_ok","children":[{"containerName":"select_field_to_edit_ok","definition":"my","kind":13,"localvar":"my","line":1082,"name":"$self"},{"line":1083,"name":"$test","kind":13,"localvar":"my","containerName":"select_field_to_edit_ok","definition":"my"},{"kind":13,"localvar":"my","containerName":"select_field_to_edit_ok","definition":"my","line":1085,"name":"$result"},{"name":"$self","kind":13,"line":1085,"containerName":"select_field_to_edit_ok"},{"containerName":"select_field_to_edit_ok","name":"_select_item_row_to_edit_ok","kind":12,"line":1085},{"containerName":"select_field_to_edit_ok","line":1087,"kind":13,"name":"$test"},{"containerName":"select_field_to_edit_ok","name":"release","line":1087,"kind":12},{"kind":13,"line":1088,"name":"$result","containerName":"select_field_to_edit_ok"}],"line":1081},{"name":"context","line":1083,"kind":12},{"range":{"end":{"character":9999,"line":1105},"start":{"character":0,"line":1097}},"kind":12,"containerName":"main::","definition":"sub","children":[{"containerName":"select_group_to_edit_ok","definition":"my","kind":13,"localvar":"my","line":1098,"name":"$self"},{"containerName":"select_group_to_edit_ok","definition":"my","kind":13,"localvar":"my","line":1099,"name":"$test"},{"name":"$result","line":1101,"containerName":"select_group_to_edit_ok","definition":"my","localvar":"my","kind":13},{"line":1101,"kind":13,"name":"$self","containerName":"select_group_to_edit_ok"},{"containerName":"select_group_to_edit_ok","name":"_select_item_row_to_edit_ok","kind":12,"line":1101},{"name":"$test","kind":13,"line":1103,"containerName":"select_group_to_edit_ok"},{"kind":12,"line":1103,"name":"release","containerName":"select_group_to_edit_ok"},{"line":1104,"kind":13,"name":"$result","containerName":"select_group_to_edit_ok"}],"name":"select_group_to_edit_ok","line":1097},{"name":"context","line":1099,"kind":12},{"containerName":"main::","definition":"sub","kind":12,"range":{"end":{"character":9999,"line":1128},"start":{"line":1113,"character":0}},"line":1113,"children":[{"name":"$self","line":1114,"localvar":"my","kind":13,"definition":"my","containerName":"select_table_to_edit_ok"},{"name":"$test","line":1115,"containerName":"select_table_to_edit_ok","definition":"my","localvar":"my","kind":13},{"localvar":"my","kind":13,"containerName":"select_table_to_edit_ok","definition":"my","name":"$result","line":1117},{"name":"$self","line":1117,"kind":13,"containerName":"select_table_to_edit_ok"},{"containerName":"select_table_to_edit_ok","name":"_select_item_row_to_edit_ok","kind":12,"line":1117},{"name":"$edit_el","line":1118,"localvar":"my","kind":13,"definition":"my","containerName":"select_table_to_edit_ok"},{"name":"$self","kind":13,"line":1118,"containerName":"select_table_to_edit_ok"},{"line":1118,"kind":12,"name":"gads","containerName":"select_table_to_edit_ok"},{"containerName":"select_table_to_edit_ok","line":1118,"kind":12,"name":"webdriver"},{"line":1118,"kind":12,"name":"find","containerName":"select_table_to_edit_ok"},{"containerName":"select_table_to_edit_ok","name":"$result","line":1123,"kind":13},{"containerName":"select_table_to_edit_ok","kind":13,"line":1123,"name":"$edit_el"},{"name":"$edit_el","kind":13,"line":1124,"containerName":"select_table_to_edit_ok"},{"name":"click","line":1124,"kind":12,"containerName":"select_table_to_edit_ok"},{"containerName":"select_table_to_edit_ok","name":"$edit_el","kind":13,"line":1124},{"containerName":"select_table_to_edit_ok","name":"$test","kind":13,"line":1126},{"containerName":"select_table_to_edit_ok","kind":12,"line":1126,"name":"release"},{"name":"$result","kind":13,"line":1127,"containerName":"select_table_to_edit_ok"}],"name":"select_table_to_edit_ok"},{"line":1115,"kind":12,"name":"context"},{"name":"method","kind":12,"line":1120},{"kind":12,"line":1121,"name":"dies"},{"line":1130,"children":[{"localvar":"my","kind":13,"definition":"my","containerName":"_select_item_row_to_edit_ok","name":"$self","line":1131},{"containerName":"_select_item_row_to_edit_ok","name":"$name","kind":13,"line":1131},{"containerName":"_select_item_row_to_edit_ok","line":1131,"kind":13,"name":"$item_row_name"},{"name":"$type_name","line":1131,"kind":13,"containerName":"_select_item_row_to_edit_ok"},{"containerName":"_select_item_row_to_edit_ok","name":"$name","line":1132,"kind":13},{"line":1133,"name":"$test","containerName":"_select_item_row_to_edit_ok","definition":"my","kind":13,"localvar":"my"},{"containerName":"_select_item_row_to_edit_ok","definition":"my","kind":13,"localvar":"my","line":1135,"name":"$item_el"},{"containerName":"_select_item_row_to_edit_ok","line":1135,"kind":13,"name":"$self"},{"kind":12,"line":1135,"name":"_find_named_item_row_el","containerName":"_select_item_row_to_edit_ok"},{"name":"$item_row_name","line":1135,"kind":13,"containerName":"_select_item_row_to_edit_ok"},{"localvar":"my","kind":13,"containerName":"_select_item_row_to_edit_ok","definition":"my","name":"$success","line":1136},{"name":"$self","kind":13,"line":1136,"containerName":"_select_item_row_to_edit_ok"},{"name":"_check_only_one","line":1136,"kind":12,"containerName":"_select_item_row_to_edit_ok"},{"containerName":"_select_item_row_to_edit_ok","name":"$item_el","line":1137,"kind":13},{"line":1139,"name":"$a_el","kind":13,"localvar":"my","containerName":"_select_item_row_to_edit_ok","definition":"my"},{"name":"$item_el","kind":13,"line":1139,"containerName":"_select_item_row_to_edit_ok"},{"containerName":"_select_item_row_to_edit_ok","line":1139,"kind":12,"name":"find"},{"line":1140,"kind":13,"name":"$a_el","containerName":"_select_item_row_to_edit_ok"},{"containerName":"_select_item_row_to_edit_ok","kind":12,"line":1140,"name":"size"},{"containerName":"_select_item_row_to_edit_ok","kind":13,"line":1140,"name":"$item_el"},{"name":"$a_el","kind":13,"line":1140,"containerName":"_select_item_row_to_edit_ok"},{"containerName":"_select_item_row_to_edit_ok","kind":13,"line":1142,"name":"$item_el"},{"containerName":"_select_item_row_to_edit_ok","name":"click","line":1142,"kind":12},{"kind":13,"line":1142,"name":"$success","containerName":"_select_item_row_to_edit_ok"},{"containerName":"_select_item_row_to_edit_ok","name":"$test","kind":13,"line":1143},{"kind":12,"line":1143,"name":"ok","containerName":"_select_item_row_to_edit_ok"},{"name":"$success","kind":13,"line":1143,"containerName":"_select_item_row_to_edit_ok"},{"line":1143,"kind":13,"name":"$name","containerName":"_select_item_row_to_edit_ok"},{"containerName":"_select_item_row_to_edit_ok","kind":13,"line":1145,"name":"$test"},{"line":1145,"kind":12,"name":"release","containerName":"_select_item_row_to_edit_ok"},{"containerName":"_select_item_row_to_edit_ok","name":"$self","line":1146,"kind":13}],"name":"_select_item_row_to_edit_ok","kind":12,"range":{"start":{"character":0,"line":1130},"end":{"character":9999,"line":1147}},"definition":"sub","signature":{"documentation":"","label":"_select_item_row_to_edit_ok($self,$name,$item_row_name,$type_name)","parameters":[{"label":"$self"},{"label":"$name"},{"label":"$item_row_name"},{"label":"$type_name"}]},"detail":"($self,$name,$item_row_name,$type_name)","containerName":"main::"},{"kind":12,"line":1133,"name":"context"},{"kind":12,"line":1139,"name":"dies"},{"detail":"($self,$name,$record_name)","signature":{"parameters":[{"label":"$self"},{"label":"$name"},{"label":"$record_name"}],"label":"select_record_to_view_ok($self,$name,$record_name)","documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n\n# Very similar to delete_current_view_ok()\nsub delete_viewed_record_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently viewed record';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n    my $record_title = $webdriver->find('h2')->text;\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ '.btn-delete' ], jquery => 1 );\n\n    $test->note(\"About to delete $record_title\");\n    $webdriver->find('#modaldelete .btn-primary.submit_button')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 follow_link_ok\n\nTakes a string and follows a link containing that string's text.\n\n\nsub follow_link_ok {\n    my ( $self, $name, $link_text ) = @_;\n    $name //= \"Follow the link containing '${link_text}'\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $link_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//main//a[ contains( ., '${link_text}') ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one(\n        $link_el, \"link containing '${link_text}'\"); ;\n    $link_el->click if $success;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 navigate_ok\n\nTakes an array reference of selectors to click on in the site navigation.\n\n\nsub navigate_ok {\n    my ( $self, $name, $selectors_ref ) = @_;\n    $name //= \"Navigate to \" . join \" \", @$selectors_ref;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure = $self->_find_and_click($selectors_ref);\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _find_and_click {\n    my ( $self, $selectors_ref, %arg ) = @_;\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $selector (@$selectors_ref) {\n        # TODO: Move 'tries' to configuration\n        my $found_el = $webdriver->find( $selector, dies => 0, tries => 25 );\n        if ( 0 == $found_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( !$found_el->visible ) {\n            push @failure, \"No visible elements matching '${selector}' found\";\n        }\n        else {\n            # TODO: Avoid using a special approach for when jQuery and\n            # WebDriver handle clicks differently\n            if ( exists $arg{jquery} and $arg{jquery} ) {\n                $webdriver->js( qq[ \\$(\"${selector}\").click() ]);\n            }\n            else {\n                $found_el->click;\n            }\n        }\n    }\n\n    return @failure;\n}\n\n=head3 purge_deleted_records_ok\n\nPurge all deleted records from the current table.\n\n\nsub purge_deleted_records_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Purge all deleted records from the current table';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    $test->note('About to purge the deleted records');\n    my @failure = $self->_find_and_click( [ \"#admin-menu\", \".manage-deleted\" ] );\n    my $title_el = $webdriver->find( 'h2', dies => 0, tries => 10 );\n    push @failure, $self->_check_element_against_expectation(\n        $title_el, { text => 'Manage deleted records' } );\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    push @failure, $self->_find_and_click([\n        '#selectall',\n        'button[data-target=\"#purge\"]',\n    ]);\n    $webdriver->find('button[type=\"submit\"][name=\"purge\"]')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n    $test->release;\n\n    return $self;\n}\n\n=head3 select_current_user_to_edit_ok\n\nFrom the I<< Manage users >> page, select the currently logged in user.\n\n\nsub select_current_user_to_edit_ok {\n    my ( $self, $name ) = @_;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok(\n        $name, $self->gads->username, 'user' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_field_to_edit_ok\n\nFrom the I<< Manage fields >> page, select a named field to edit.\n\n\nsub select_field_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'field' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_group_to_edit_ok\n\nFrom the I<< Groups >> page, select a named group to edit.\n\n\nsub select_group_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'group' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_table_to_edit_ok\n\nFrom the I<< Manage tables >> page, select a named table to edit.\n\n\nsub select_table_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'table' );\n    my $edit_el = $self->gads->webdriver->find(\n        '//*[contains( @class, \"list--tabs\")]//a[contains( ., \"Edit table\")]',\n        method => 'xpath',\n        dies => 0,\n    );\n    $result &&= $edit_el;\n    $edit_el->click if $edit_el;\n\n    $test->release;\n    return $result;\n}\n\nsub _select_item_row_to_edit_ok {\n    my ( $self, $name, $item_row_name, $type_name ) = @_;\n    $name //= \"Select the '${item_row_name}' ${type_name} to edit\";\n    my $test = context();\n\n    my $item_el = $self->_find_named_item_row_el($item_row_name);\n    my $success = $self->_check_only_one(\n        $item_el, \"${type_name} named '${item_row_name}'\" );\n\n    my $a_el = $item_el->find( 'a', dies => 0 );\n    if ( $a_el->size ) { $item_el = $a_el }\n\n    $item_el->click if $success;\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 select_record_to_view_ok\n\nFrom the I<< See records >> page, select a named record to view."},"definition":"sub","containerName":"main::","kind":12,"range":{"start":{"character":0,"line":1155},"end":{"line":1171,"character":9999}},"line":1155,"name":"select_record_to_view_ok","children":[{"line":1156,"name":"$self","definition":"my","containerName":"select_record_to_view_ok","kind":13,"localvar":"my"},{"containerName":"select_record_to_view_ok","kind":13,"line":1156,"name":"$name"},{"containerName":"select_record_to_view_ok","kind":13,"line":1156,"name":"$record_name"},{"containerName":"select_record_to_view_ok","name":"$name","kind":13,"line":1157},{"line":1158,"name":"$test","definition":"my","containerName":"select_record_to_view_ok","kind":13,"localvar":"my"},{"line":1160,"name":"$webdriver","definition":"my","co