el","kind":13,"line":1216},{"containerName":"submit_add_a_field_form_ok","kind":13,"line":1217,"name":"$success"},{"containerName":"submit_add_a_field_form_ok","name":"$group_option_el","line":1218,"kind":13},{"line":1218,"kind":12,"name":"click","containerName":"submit_add_a_field_form_ok"},{"containerName":"submit_add_a_field_form_ok","kind":12,"line":1220,"name":"click"},{"containerName":"submit_add_a_field_form_ok","line":1220,"kind":13,"name":"$webdriver"},{"name":"find","line":1220,"kind":12,"containerName":"submit_add_a_field_form_ok"},{"containerName":"submit_add_a_field_form_ok","name":"$webdriver","kind":13,"line":1221},{"name":"find","line":1221,"kind":12,"containerName":"submit_add_a_field_form_ok"},{"name":"click","kind":12,"line":1221,"containerName":"submit_add_a_field_form_ok"},{"kind":13,"line":1224,"name":"$test","containerName":"submit_add_a_field_form_ok"},{"line":1224,"kind":12,"name":"note","containerName":"submit_add_a_field_form_ok"},{"name":"$webdriver","kind":13,"line":1225,"containerName":"submit_add_a_field_form_ok"},{"name":"find","line":1225,"kind":12,"containerName":"submit_add_a_field_form_ok"},{"containerName":"submit_add_a_field_form_ok","name":"click","kind":12,"line":1225},{"containerName":"submit_add_a_field_form_ok","definition":"my","localvar":"my","kind":13,"name":"$result","line":1227},{"containerName":"submit_add_a_field_form_ok","name":"$test","kind":13,"line":1227},{"containerName":"submit_add_a_field_form_ok","line":1227,"kind":12,"name":"ok"},{"name":"$success","line":1227,"kind":13,"containerName":"submit_add_a_field_form_ok"},{"containerName":"submit_add_a_field_form_ok","kind":13,"line":1227,"name":"$name"},{"containerName":"submit_add_a_field_form_ok","kind":13,"line":1228,"name":"$test"},{"kind":12,"line":1228,"name":"release","containerName":"submit_add_a_field_form_ok"},{"containerName":"submit_add_a_field_form_ok","line":1229,"kind":13,"name":"$result"}],"kind":12,"range":{"start":{"character":0,"line":1182},"end":{"line":1230,"character":9999}},"detail":"($self,$name,$args_ref)","signature":{"parameters":[{"label":"$self"},{"label":"$name"},{"label":"$args_ref"}],"documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n\n# Very similar to delete_current_view_ok()\nsub delete_viewed_record_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently viewed record';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n    my $record_title = $webdriver->find('h2')->text;\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ '.btn-delete' ], jquery => 1 );\n\n    $test->note(\"About to delete $record_title\");\n    $webdriver->find('#modaldelete .btn-primary.submit_button')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 follow_link_ok\n\nTakes a string and follows a link containing that string's text.\n\n\nsub follow_link_ok {\n    my ( $self, $name, $link_text ) = @_;\n    $name //= \"Follow the link containing '${link_text}'\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $link_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//main//a[ contains( ., '${link_text}') ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one(\n        $link_el, \"link containing '${link_text}'\"); ;\n    $link_el->click if $success;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 navigate_ok\n\nTakes an array reference of selectors to click on in the site navigation.\n\n\nsub navigate_ok {\n    my ( $self, $name, $selectors_ref ) = @_;\n    $name //= \"Navigate to \" . join \" \", @$selectors_ref;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure = $self->_find_and_click($selectors_ref);\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _find_and_click {\n    my ( $self, $selectors_ref, %arg ) = @_;\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $selector (@$selectors_ref) {\n        # TODO: Move 'tries' to configuration\n        my $found_el = $webdriver->find( $selector, dies => 0, tries => 25 );\n        if ( 0 == $found_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( !$found_el->visible ) {\n            push @failure, \"No visible elements matching '${selector}' found\";\n        }\n        else {\n            # TODO: Avoid using a special approach for when jQuery and\n            # WebDriver handle clicks differently\n            if ( exists $arg{jquery} and $arg{jquery} ) {\n                $webdriver->js( qq[ \\$(\"${selector}\").click() ]);\n            }\n            else {\n                $found_el->click;\n            }\n        }\n    }\n\n    return @failure;\n}\n\n=head3 purge_deleted_records_ok\n\nPurge all deleted records from the current table.\n\n\nsub purge_deleted_records_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Purge all deleted records from the current table';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    $test->note('About to purge the deleted records');\n    my @failure = $self->_find_and_click( [ \"#admin-menu\", \".manage-deleted\" ] );\n    my $title_el = $webdriver->find( 'h2', dies => 0, tries => 10 );\n    push @failure, $self->_check_element_against_expectation(\n        $title_el, { text => 'Manage deleted records' } );\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    push @failure, $self->_find_and_click([\n        '#selectall',\n        'button[data-target=\"#purge\"]',\n    ]);\n    $webdriver->find('button[type=\"submit\"][name=\"purge\"]')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n    $test->release;\n\n    return $self;\n}\n\n=head3 select_current_user_to_edit_ok\n\nFrom the I<< Manage users >> page, select the currently logged in user.\n\n\nsub select_current_user_to_edit_ok {\n    my ( $self, $name ) = @_;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok(\n        $name, $self->gads->username, 'user' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_field_to_edit_ok\n\nFrom the I<< Manage fields >> page, select a named field to edit.\n\n\nsub select_field_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'field' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_group_to_edit_ok\n\nFrom the I<< Groups >> page, select a named group to edit.\n\n\nsub select_group_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'group' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_table_to_edit_ok\n\nFrom the I<< Manage tables >> page, select a named table to edit.\n\n\nsub select_table_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'table' );\n    my $edit_el = $self->gads->webdriver->find(\n        '//*[contains( @class, \"list--tabs\")]//a[contains( ., \"Edit table\")]',\n        method => 'xpath',\n        dies => 0,\n    );\n    $result &&= $edit_el;\n    $edit_el->click if $edit_el;\n\n    $test->release;\n    return $result;\n}\n\nsub _select_item_row_to_edit_ok {\n    my ( $self, $name, $item_row_name, $type_name ) = @_;\n    $name //= \"Select the '${item_row_name}' ${type_name} to edit\";\n    my $test = context();\n\n    my $item_el = $self->_find_named_item_row_el($item_row_name);\n    my $success = $self->_check_only_one(\n        $item_el, \"${type_name} named '${item_row_name}'\" );\n\n    my $a_el = $item_el->find( 'a', dies => 0 );\n    if ( $a_el->size ) { $item_el = $a_el }\n\n    $item_el->click if $success;\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 select_record_to_view_ok\n\nFrom the I<< See records >> page, select a named record to view.\n\n\nsub select_record_to_view_ok {\n    my ( $self, $name, $record_name ) = @_;\n    $name //= \"Select the '${record_name}' record to view\";\n    my $test = context();\n\n    my $webdriver = $self->gads->webdriver;\n    my $xpath = \"//tr[ contains( ., '${record_name}') ]//td[1]//a[1]\";\n    my $link_el = $webdriver->find( $xpath, method => 'xpath', dies => 0 );\n    my $success = $self->_check_only_one(\n        $link_el, \"record named '${record_name}'\" );\n\n    $link_el->click if $success;\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 submit_add_a_field_form_ok\n\nSubmit the I<< Add a field >> form.  Takes a hash reference of arguments\nwhere C<< name >> contains the name of the new field to add, C<< type >>\nthe name of its type, and C<< group_name >> contains the name of an\nexisting group to assign all permissions to.","label":"submit_add_a_field_form_ok($self,$name,$args_ref)"},"definition":"sub","containerName":"main::"},{"line":1187,"kind":12,"name":"context"},{"kind":12,"line":1190,"name":"name"},{"name":"method","line":1193,"kind":12},{"name":"method","line":1204,"kind":12},{"name":"method","kind":12,"line":1212},{"kind":12,"line":1213,"name":"dies"},{"name":"submit_add_a_group_form_ok","children":[{"line":1239,"name":"$self","kind":13,"localvar":"my","definition":"my","containerName":"submit_add_a_group_form_ok"},{"containerName":"submit_add_a_group_form_ok","line":1239,"kind":13,"name":"$name"},{"kind":13,"line":1239,"name":"$group_name","containerName":"submit_add_a_group_form_ok"},{"containerName":"submit_add_a_group_form_ok","name":"$name","kind":13,"line":1240},{"definition":"my","containerName":"submit_add_a_group_form_ok","localvar":"my","kind":13,"name":"$test","line":1242},{"line":1243,"name":"$success","kind":13,"localvar":"my","definition":"my","containerName":"submit_add_a_group_form_ok"},{"line":1243,"kind":13,"name":"$self","containerName":"submit_add_a_group_form_ok"},{"name":"_fill_in_field","line":1243,"kind":12,"containerName":"submit_add_a_group_form_ok"},{"name":"$group_name","line":1243,"kind":13,"containerName":"submit_add_a_group_form_ok"},{"containerName":"submit_add_a_group_form_ok","kind":13,"line":1245,"name":"$test"},{"containerName":"submit_add_a_group_form_ok","name":"note","line":1245,"kind":12},{"containerName":"submit_add_a_group_form_ok","kind":13,"line":1246,"name":"$success"},{"line":1246,"kind":13,"name":"$self","containerName":"submit_add_a_group_form_ok"},{"kind":12,"line":1246,"name":"_click_submit_button","containerName":"submit_add_a_group_form_ok"},{"containerName":"submit_add_a_group_form_ok","definition":"my","localvar":"my","kind":13,"name":"$result","line":1248},{"kind":13,"line":1248,"name":"$test","containerName":"submit_add_a_group_form_ok"},{"containerName":"submit_add_a_group_form_ok","name":"ok","line":1248,"kind":12},{"containerName":"submit_add_a_group_form_ok","kind":13,"line":1248,"name":"$success"},{"containerName":"submit_add_a_group_form_ok","name":"$name","line":1248,"kind":13},{"containerName":"submit_add_a_group_form_ok","line":1249,"kind":13,"name":"$test"},{"containerName":"submit_add_a_group_form_ok","name":"release","line":1249,"kind":12},{"containerName":"submit_add_a_group_form_ok","kind":13,"line":1250,"name":"$result"}],"line":1238,"range":{"start":{"line":1238,"character":0},"end":{"character":9999,"line":1251}},"kind":12,"signature":{"label":"submit_add_a_group_form_ok($self,$name,$group_name)","documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n\n# Very similar to delete_current_view_ok()\nsub delete_viewed_record_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently viewed record';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n    my $record_title = $webdriver->find('h2')->text;\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ '.btn-delete' ], jquery => 1 );\n\n    $test->note(\"About to delete $record_title\");\n    $webdriver->find('#modaldelete .btn-primary.submit_button')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 follow_link_ok\n\nTakes a string and follows a link containing that string's text.\n\n\nsub follow_link_ok {\n    my ( $self, $name, $link_text ) = @_;\n    $name //= \"Follow the link containing '${link_text}'\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $link_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//main//a[ contains( ., '${link_text}') ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one(\n        $link_el, \"link containing '${link_text}'\"); ;\n    $link_el->click if $success;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 navigate_ok\n\nTakes an array reference of selectors to click on in the site navigation.\n\n\nsub navigate_ok {\n    my ( $self, $name, $selectors_ref ) = @_;\n    $name //= \"Navigate to \" . join \" \", @$selectors_ref;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure = $self->_find_and_click($selectors_ref);\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _find_and_click {\n    my ( $self, $selectors_ref, %arg ) = @_;\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $selector (@$selectors_ref) {\n        # TODO: Move 'tries' to configuration\n        my $found_el = $webdriver->find( $selector, dies => 0, tries => 25 );\n        if ( 0 == $found_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( !$found_el->visible ) {\n            push @failure, \"No visible elements matching '${selector}' found\";\n        }\n        else {\n            # TODO: Avoid using a special approach for when jQuery and\n            # WebDriver handle clicks differently\n            if ( exists $arg{jquery} and $arg{jquery} ) {\n                $webdriver->js( qq[ \\$(\"${selector}\").click() ]);\n            }\n            else {\n                $found_el->click;\n            }\n        }\n    }\n\n    return @failure;\n}\n\n=head3 purge_deleted_records_ok\n\nPurge all deleted records from the current table.\n\n\nsub purge_deleted_records_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Purge all deleted records from the current table';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    $test->note('About to purge the deleted records');\n    my @failure = $self->_find_and_click( [ \"#admin-menu\", \".manage-deleted\" ] );\n    my $title_el = $webdriver->find( 'h2', dies => 0, tries => 10 );\n    push @failure, $self->_check_element_against_expectation(\n        $title_el, { text => 'Manage deleted records' } );\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    push @failure, $self->_find_and_click([\n        '#selectall',\n        'button[data-target=\"#purge\"]',\n    ]);\n    $webdriver->find('button[type=\"submit\"][name=\"purge\"]')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n    $test->release;\n\n    return $self;\n}\n\n=head3 select_current_user_to_edit_ok\n\nFrom the I<< Manage users >> page, select the currently logged in user.\n\n\nsub select_current_user_to_edit_ok {\n    my ( $self, $name ) = @_;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok(\n        $name, $self->gads->username, 'user' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_field_to_edit_ok\n\nFrom the I<< Manage fields >> page, select a named field to edit.\n\n\nsub select_field_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'field' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_group_to_edit_ok\n\nFrom the I<< Groups >> page, select a named group to edit.\n\n\nsub select_group_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'group' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_table_to_edit_ok\n\nFrom the I<< Manage tables >> page, select a named table to edit.\n\n\nsub select_table_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'table' );\n    my $edit_el = $self->gads->webdriver->find(\n        '//*[contains( @class, \"list--tabs\")]//a[contains( ., \"Edit table\")]',\n        method => 'xpath',\n        dies => 0,\n    );\n    $result &&= $edit_el;\n    $edit_el->click if $edit_el;\n\n    $test->release;\n    return $result;\n}\n\nsub _select_item_row_to_edit_ok {\n    my ( $self, $name, $item_row_name, $type_name ) = @_;\n    $name //= \"Select the '${item_row_name}' ${type_name} to edit\";\n    my $test = context();\n\n    my $item_el = $self->_find_named_item_row_el($item_row_name);\n    my $success = $self->_check_only_one(\n        $item_el, \"${type_name} named '${item_row_name}'\" );\n\n    my $a_el = $item_el->find( 'a', dies => 0 );\n    if ( $a_el->size ) { $item_el = $a_el }\n\n    $item_el->click if $success;\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 select_record_to_view_ok\n\nFrom the I<< See records >> page, select a named record to view.\n\n\nsub select_record_to_view_ok {\n    my ( $self, $name, $record_name ) = @_;\n    $name //= \"Select the '${record_name}' record to view\";\n    my $test = context();\n\n    my $webdriver = $self->gads->webdriver;\n    my $xpath = \"//tr[ contains( ., '${record_name}') ]//td[1]//a[1]\";\n    my $link_el = $webdriver->find( $xpath, method => 'xpath', dies => 0 );\n    my $success = $self->_check_only_one(\n        $link_el, \"record named '${record_name}'\" );\n\n    $link_el->click if $success;\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 submit_add_a_field_form_ok\n\nSubmit the I<< Add a field >> form.  Takes a hash reference of arguments\nwhere C<< name >> contains the name of the new field to add, C<< type >>\nthe name of its type, and C<< group_name >> contains the name of an\nexisting group to assign all permissions to.\n\n\nsub submit_add_a_field_form_ok {\n    my ( $self, $name, $args_ref ) = @_;\n    $name //= 'Submit the add a field form';\n    my %arg = %$args_ref;\n\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $success = $self->_fill_in_field( 'input#name', $arg{name} );\n    my $type_el = $webdriver->find(\n        \"//*[ \\@id = 'type' ]/option[ text() = '$arg{type}' ]\",\n        method => 'xpath',\n    );\n    $success &&= $self->_check_only_one(\n        $type_el, \"type named '$arg{type}'\" );\n    $type_el->click if $success;\n\n    # Fill in checkboxes to give the specified group all permissions\n    my $permissions_tab_el = $webdriver->find('#permissions-tab')->click;\n    # Check the Permissions tab heading is shown\n    $webdriver->find(\n        '//h3[ contains( ., \"Permissions\" ) ]',\n        method => 'xpath',\n    );\n    # Click \"Add permissions\" button\n    $webdriver->find('#configure-permissions')->click;\n    # Select the desired group from the drop-down\n    my $group_option_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//select[ \\@id = 'select-permission-group' ]/option[ contains( ., '$arg{group_name}' ) ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n    $success &&= $self->_check_only_one(\n        $group_option_el, \"group named '$arg{group_name}'\" );\n    if ($success) {\n        $group_option_el->click;\n        # Tick all \"access rights\" checkboxes, then submit the form\n        $_->click foreach $webdriver->find('.permission-rule input[name^=permission_]');\n        $webdriver->find('#add-permission-rule')->click;\n    }\n\n    $test->note(\"About to add a field named $arg{name}\");\n    $webdriver->find('#submit_save')->click;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 submit_add_a_group_form_ok\n\nSubmit the I<< Add a group >> form.","parameters":[{"label":"$self"},{"label":"$name"},{"label":"$group_name"}]},"definition":"sub","detail":"($self,$name,$group_name)","containerName":"main::"},{"name":"context","kind":12,"line":1242},{"containerName":"main::","definition":"sub","signature":{"parameters":[{"label":"$self"},{"label":"$name"},{"label":"$args_ref"}],"label":"submit_add_a_table_form_ok($self,$name,$args_ref)","documentation":"1;\npackage Test::GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse GADSDriver ();\nuse List::Util 'zip';\nuse Test2::API 'context';\nuse Test2::Tools::Compare qw( is like unlike );\n\n=head1 NAME\n\nTest::GADSDriver - GADS WebDriver integration test library\n\n=head1 EXAMPLES\n\nSee files with the C<< .t >> suffix in the F<< webdriver/t >> directory.\n\n=head1 CONSTRUCTOR METHOD\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 gads\n\nA L<< GADSDriver >> object.\n\n\nhas gads => (\n    is => 'ro',\n    default => \\&_default_gads,\n    # TODO: Callers shouldn't need to access any delegated methods, but\n    # this is convenient in the absence of suitable test methods.\n    handles => [ 'go_to_url' ],\n);\n\nsub _default_gads {\n    GADSDriver->new;\n}\n\n=head1 TEST METHODS\n\nAll test methods take an optional first argument of a test name.  In the\nabsence of this argument, each test provides a reasonable default name.\n\nSome methods take additional arguments.\n\n=head2 Assertion Tests\n\nThese test methods verify that the user interface is in a given state.\n\n=head3 assert_error_absent\n\nNo error message is visible.\n\n\nsub assert_error_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_error_present\n\nAn error message is visible.\n\n\nsub assert_error_present {\n    my ( $self, $name ) = @_;\n    $name //= 'An error message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_error( $name, 1 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_absent\n\nNo success message is visible.\n\n\nsub assert_success_absent {\n    my ( $self, $name ) = @_;\n    $name //= 'No success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 0 );\n    $test->release;\n    return $result;\n}\n\n=head3 assert_success_present\n\nA success message is visible.\n\n\nsub assert_success_present {\n    my ( $self, $name ) = @_;\n    $name //= 'A success message is visible';\n    my $test = context();\n\n    my $result = $self->_assert_success( $name, 1 );\n    $test->release;\n    return $result;\n}\n\nsub _assert_error {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $error_el = $self->_assert_element(\n        '.alert-danger',\n        $expect_present,\n        qr/\\bERROR: /,\n        $name,\n    );\n\n    my $error_text = $error_el->text;\n    if ( $error_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The error message is '${error_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_success {\n    my ( $self, $name, $expect_present ) = @_;\n    my $test = context();\n\n    my $success_el = $self->_assert_element(\n        '.alert-success',\n        $expect_present,\n        qr/\\bNOTICE: /,\n        $name,\n    );\n\n    my $success_text = $success_el->text;\n    if ( $success_text =~ /\\S/ ) {\n        my $diagnostic_text = \"The success message is '${success_text}'\";\n        if ($expect_present) {\n            $test->note($diagnostic_text);\n        }\n        else {\n            $test->diag($diagnostic_text);\n        }\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_field_exists\n\nOn the I<< Manage fields >> page, takes two named arguments, C<< name >>\nand C<< type >> and asserts that a field with the given name of the\ngiven type is listed as existing on the current table.\n\n\nsub assert_field_exists {\n    my ( $self, $name, $args_ref ) = @_;\n    my %arg = %$args_ref;\n    $name //= \"A field named '$arg{name}' of type '$arg{type}' exists\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $type_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n       \"//main//tr/td[2][ contains( ., '$arg{name}' ) ]/../td[3]\",\n       method => 'xpath',\n       dies => 0,\n    );\n    my $success = $self->_check_only_one( $type_el, \"field named $arg{name}\" );\n\n    if ( $success && $type_el ) {\n        is( $type_el->text, $arg{type}, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_new_record_fields\n\nOn the I<< New record >> page, takes an array of hash references\ndescribing all data entry fields that should exist.\n\nEach hash reference contains the following fields:\n\n\n* label\n\nThe text contents of the human readable label element\n\n* type\n\nThe value of the C<< data-column-type >> attribute on the element in the\nC<< form-group >> class.\n\n\n\nsub assert_new_record_fields {\n    my ( $self, $name, $expected ) = @_;\n    $name //= \"The new record page shows only the expected fields\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $form_group_el = $webdriver->find('.edit-form .form-group');\n    my $found = [\n        map {\n            {\n                label => $_->find('label')->text,\n                type => $_->attr('data-column-type'),\n            },\n        } $form_group_el->split,\n    ];\n\n    is( $found, $expected, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_table_not_listed\n\nOn the I<< Manage tables >> page, takes one argument containing the name\nof a table and asserts that no table with the given name is listed.\n\n\nsub assert_table_not_listed {\n    my ( $self, $name, $table_name ) = @_;\n    $name //= \"The table named '$table_name' is not listed\";\n    my $test = context();\n\n    my $table_el = $self->_find_named_item_row_el($table_name);\n\n    my $name_selector = '../../td[ not( descendant::a ) ]';\n    my @table_name = map {$_->find( $name_selector, method => 'xpath' )->text }\n        $table_el->split;\n    is( \\@table_name, [], $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_navigation_present\n\nAssert that the navigation displayed on logged in pages is visible.\n\n\nsub assert_navigation_present {\n    my ( $self, $name ) = @_;\n    $name //= 'The site navigation is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        'nav .nav',\n        1,\n        qr/\\bHome\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_field_page\n\nThe I<< Add a field >> page is visible.\n\n\nsub assert_on_add_a_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n        { selector => '.breadcrumbs__item:nth-of-type(4)', text => 'Add a field' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_group_page\n\nThe I<< Add a group >> page is visible.\n\n\nsub assert_on_add_a_group_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a group page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Create group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_add_a_table_page\n\nThe I<< Add a table >> page is visible.\n\n\nsub assert_on_add_a_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '#newTableModal',\n        { selector => 'h3', text => 'Table setup' },\n    );\n\n    $test->release;\n    return $self;\n}\n=head3 assert_on_add_a_view_page\n\nThe I<< Add a view >> page is visisble.\n\n\nsub assert_on_add_a_view_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The add a view page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.view\\\\/0',\n        { selector => 'h2', text => 'Add a customised view' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_field_page\n\nThe I<< Edit field >> page is visible\n\n\nsub assert_on_edit_field_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit field page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.layout',\n        '#basic-panel',\n        { selector => 'h2', match => '\\\\AEdit field\\\\s*' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_edit_user_page\n\nThe user editing page is visible\n\n\nsub assert_on_edit_user_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The edit user page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', match => '\\A(?i)Edit user:' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_login_page\n\nThe login page is visible.\n\n\nsub assert_on_login_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The login page is visible';\n    my $test = context();\n\n    $self->_assert_element(\n        '.login__title',\n        1,\n        qr/\\A(?i)Please Sign In\\b/,\n        $name,\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_fields_page\n\nThe I<< Manage fields >> page is visible.\n\n\nsub assert_on_manage_fields_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage fields page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n        { selector => '.breadcrumbs__item:nth-of-type(3)', text => 'Fields' },\n    );\n    # TODO: Check the table name appears in the h1 text\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_groups_page\n\nThe I<< Groups >> page is visible.\n\n\nsub assert_on_manage_groups_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage groups page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Group' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_tables_page\n\nThe I<< Manage tables >> page is visible.\n\n\nsub assert_on_manage_tables_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage tables page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Tables' },\n        { selector => '.nav__link--active', text => 'Tables' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_this_table_page\n\nThe I<< Manage this table >> page is visible.\n\n\nsub assert_on_manage_this_table_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage this table page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        '.breadcrumbs__item',\n        { selector => '.breadcrumbs__item:nth-of-type(1)', text => 'Tables' },\n        # TODO: Match the table name\n        { selector => '.breadcrumbs__item:nth-of-type(2)', match => '\\ATable: ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_manage_users_page\n\nThe I<< Manage users >> page is visible.\n\n\nsub assert_on_manage_users_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The manage users page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        { selector => 'h1', text => 'Users' },\n        { selector => '.sr-only', match => '\\b(?i)users?\\b' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_new_record_page\n\nThe I<< New record >> page is visible.\n\n\nsub assert_on_new_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The new record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.edit',\n        { selector => 'h2', text => 'New record' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_see_records_page\n\nThe I<< See records >> page is visible.  Takes two optional arguments,\nthe test name and an expected page title.\n\n\nsub assert_on_see_records_page {\n    my ( $self, $name, $page_title ) = @_;\n    $name //= 'The see records page is visible';\n    $page_title //= 'All data';     # Default title for no view\n    my $title = quotemeta $page_title;\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        'body.page.data_table',\n        { selector => 'h1', match => \"\\\\A${title}\\\\s*\\\\z\" },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_on_view_record_page\n\nThe I<< View record >> page is visible.\n\n\nsub assert_on_view_record_page {\n    my ( $self, $name ) = @_;\n    $name //= 'The view record page is visible';\n    my $test = context();\n\n    $self->_assert_on_page(\n        $name,\n        # TODO: Check the field values appear in the page content\n        'body.page.edit',\n        { selector => 'h2', match => '\\\\ARecord ID ' },\n    );\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_record_has_fields\n\nOn the I<< View record >> page, check that a record with the specified\nfields and values is shown.\n\n\nsub assert_record_has_fields {\n    my ( $self, $name, $expected_fields_ref ) = @_;\n    $name //= 'A record with the specified fields is visible';\n    my $test = context();\n\n    my $table_el = $self->gads->webdriver->find( '#topic_show table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'table of fields' );\n\n    my %field_found;\n    foreach my $row_el ( $table_el->find('tr')->split ) {\n        my $field_el = $row_el->find('th');\n        $success &&= $self->_check_only_one( $field_el, 'field name' );\n        my $value_el = $row_el->find('td');\n        $success &&= $self->_check_only_one( $value_el, 'field value' );\n\n        $field_found{ $field_el->text } = $value_el->text;\n    }\n\n    if ($success) {\n        is( \\%field_found, $expected_fields_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\n=head3 assert_records_shown\n\nOn the I<< See Records >> page, check which records are shown.  Any\nunexpected records, duplicate records, or records displayed in an\nunexpected order cause this to fail.\n\n\nsub assert_records_shown {\n    my ( $self, $name, $expected_records_ref ) = @_;\n    $name //= 'The see records page shows the expected records';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    # TODO: Replace this and %wanted_fields further down with\n    # Test2::Tools::Compare::set().\n    my %wanted_heading = map { $_ => undef }\n        map { keys %$_ } @$expected_records_ref;\n    my @wanted_heading = keys %wanted_heading;\n\n    my $table_el = $webdriver->find( '#data-table', dies => 0 );\n    my $success = $self->_check_only_one( $table_el, 'data table' );\n\n    my $headings_el = $table_el->find( 'thead th', dies => 0 );\n    my @heading = map\n        { $_->attr('data-thlabel') // $_->attr('aria-label') }\n        $headings_el->split;\n\n    my @found_record;\n    my $records_el = $table_el->find( 'tbody tr', dies => 0 );\n    foreach my $record_el ( $records_el->split ) {\n        my @value = map $_->text, $record_el->find( 'td', dies => 0 )->split;\n        my %record = zip @heading, @value;\n        my %wanted_fields = map { $_ => $record{$_} } @wanted_heading;\n        push @found_record, \\%wanted_fields;\n    }\n\n    if ( $success ) {\n        is( \\@found_record, $expected_records_ref, $name );\n    }\n    else {\n        $test->ok( 0, $name );\n    }\n\n    $test->release;\n    return $self;\n}\n\nsub _assert_element {\n    my( $self, $selector, $expect_present, $expected_re, $name ) = @_;\n    my $test = context();\n\n    # Try for longer to find expected elements than unexpected elements.\n    # TODO: Move these to configuration\n    my $tries = $expect_present ? 30 : 10;\n\n    my $matching_el = $self->gads->webdriver->find(\n        $selector,\n        dies => 0,\n        tries => $tries,\n    );\n\n    if ( 0 == $matching_el->size ) {\n        $test->ok( !$expect_present, $name );\n        if ($expect_present) {\n            $test->diag( \"No element matching '${selector}' found\" );\n        }\n    }\n    else {\n        my $matching_text = $matching_el->text;\n        if ($expect_present) {\n            like( $matching_text, $expected_re, $name );\n        }\n        else {\n            unlike( $matching_text, $expected_re, $name );\n        }\n    }\n\n    $test->release;\n    return $matching_el;\n}\n\n# Note: the first expression should always be a page ID, not a complex\n# hashref selector, as these don't check the full condition in a find()\n# call but instead use _check_element_against_expectation().\nsub _assert_on_page {\n    my ( $self, $name, @expectation ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $expect (@expectation) {\n        # Expectations can contain a string or a hashref of arguments\n        my $selector = ref($expect) ? $expect->{selector} : $expect;\n\n        # TODO: Move 'tries' to configuration\n        my $matching_el = $webdriver->find( $selector, dies => 0, tries => 50 );\n\n        if ( 0 == $matching_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( ref $expect ) {\n            push @failure, $self->_check_element_against_expectation(\n                $matching_el, $expect );\n        }\n    }\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _check_element_against_expectation {\n    my ( $self, $matching_el, $expect_ref ) = @_;\n    my $matching_text = $matching_el->text;\n    my %expect = %$expect_ref;\n\n    my @failure;\n    if ( exists $expect{text} && exists $expect{match} ) {\n        push @failure, \"Both 'match' and 'text' expectations stated\";\n    }\n    elsif ( exists $expect{text} ) {\n        if ( $matching_text ne $expect{text} ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{text}'\";\n        }\n    }\n    elsif ( exists $expect{match} ) {\n        if ( $matching_text !~ /$expect{match}/ ) {\n            push @failure, \"Found '${matching_text}' in $expect{selector}, expected '$expect{match}'\";\n        }\n    }\n    else {\n        push @failure, \"No 'match' or 'text' expectation stated\";\n    }\n\n    return @failure;\n}\n\n=head2 Action Methods\n\nThese test methods perform actions against the user interface.\n\n=head3 assign_current_user_to_group_ok\n\nAssign the currently logged in user to a specified group.\n\n\nsub assign_current_user_to_group_ok {\n    my ( $self, $name, $group_name ) = @_;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $query = \"//label[ contains(., '${group_name}') ]/../input[\n            \\@type = 'checkbox'\n            and \\@name = 'groups'\n        ]\";\n    my $checkbox_el = $webdriver->find( $query,\n        method => 'xpath', dies => 0, tries => 40 );\n\n    my $description = \"checkbox for group '${group_name}'\";\n    my $success = $self->_check_only_one( $checkbox_el, $description );\n    if ( $checkbox_el->selected ) {\n        $success = 0;\n        $test->diag(\"The ${description} is unexpectedly selected\");\n    }\n    $checkbox_el->find('../label', method => 'xpath')->click;\n\n    my $group_id = $checkbox_el->attr('value');\n    $webdriver->find( \"input[name='groups'][value='${group_id}']:checked\" );\n    $success &&= $self->_click_submit_button;\n\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 confirm_deletion_ok\n\nDelete the current table from the I<< Manage this table >> page.\n\nCommonly used to delete a field or table.\n\n\nsub confirm_deletion_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Approve the \"Confirm deletion\" modal';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $entity_name = $webdriver->find(\n        'input[name=\"name\"]',\n        tries => 50,\n    )->attr('value');\n\n    my $delete_button_el = $webdriver->find(\n        'button.btn-js-delete',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one( $delete_button_el, 'delete button' );\n    if ($success) {\n        $delete_button_el->click;\n\n        my $selector = '.modal-content button[name=delete]';\n        my $confirm_button_el = $webdriver->find( $selector, dies => 0 );\n\n        if ( 1 == $confirm_button_el->size ) {\n            $test->note( qq{About to delete \"$entity_name\"} );\n            $confirm_button_el->click;\n        }\n        else {\n            $success = 0;\n            $test->diag(\"No confirm button found\");\n        }\n    }\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 delete_current_view_ok\n\nDelete the currently displayed view\n\n\n# Very similar to delete_viewed_record_ok()\nsub delete_current_view_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently displayed view';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $view_name = $webdriver->find('input#name')->attr('value');\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ 'a[data-target=\"#myModal\"]' ] );\n\n    $test->note(\"About to delete view ${view_name}\");\n    $webdriver->find('#myModal .modal-dialog .btn-primary')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 delete_viewed_record_ok\n\nDelete the currently viewed record\n\n\n# Very similar to delete_current_view_ok()\nsub delete_viewed_record_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Delete the currently viewed record';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n    my $record_title = $webdriver->find('h2')->text;\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    my @failure = $self->_find_and_click( [ '.btn-delete' ], jquery => 1 );\n\n    $test->note(\"About to delete $record_title\");\n    $webdriver->find('#modaldelete .btn-primary.submit_button')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self\n}\n\n=head3 follow_link_ok\n\nTakes a string and follows a link containing that string's text.\n\n\nsub follow_link_ok {\n    my ( $self, $name, $link_text ) = @_;\n    $name //= \"Follow the link containing '${link_text}'\";\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $link_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//main//a[ contains( ., '${link_text}') ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n\n    my $success = $self->_check_only_one(\n        $link_el, \"link containing '${link_text}'\"); ;\n    $link_el->click if $success;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 navigate_ok\n\nTakes an array reference of selectors to click on in the site navigation.\n\n\nsub navigate_ok {\n    my ( $self, $name, $selectors_ref ) = @_;\n    $name //= \"Navigate to \" . join \" \", @$selectors_ref;\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure = $self->_find_and_click($selectors_ref);\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n\n    $test->release;\n    return $self;\n}\n\nsub _find_and_click {\n    my ( $self, $selectors_ref, %arg ) = @_;\n    my $webdriver = $self->gads->webdriver;\n\n    my @failure;\n    foreach my $selector (@$selectors_ref) {\n        # TODO: Move 'tries' to configuration\n        my $found_el = $webdriver->find( $selector, dies => 0, tries => 25 );\n        if ( 0 == $found_el->size ) {\n            push @failure, \"No elements matching '${selector}' found\";\n        }\n        elsif ( !$found_el->visible ) {\n            push @failure, \"No visible elements matching '${selector}' found\";\n        }\n        else {\n            # TODO: Avoid using a special approach for when jQuery and\n            # WebDriver handle clicks differently\n            if ( exists $arg{jquery} and $arg{jquery} ) {\n                $webdriver->js( qq[ \\$(\"${selector}\").click() ]);\n            }\n            else {\n                $found_el->click;\n            }\n        }\n    }\n\n    return @failure;\n}\n\n=head3 purge_deleted_records_ok\n\nPurge all deleted records from the current table.\n\n\nsub purge_deleted_records_ok {\n    my ( $self, $name ) = @_;\n    $name //= 'Purge all deleted records from the current table';\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    $test->note('About to purge the deleted records');\n    my @failure = $self->_find_and_click( [ \"#admin-menu\", \".manage-deleted\" ] );\n    my $title_el = $webdriver->find( 'h2', dies => 0, tries => 10 );\n    push @failure, $self->_check_element_against_expectation(\n        $title_el, { text => 'Manage deleted records' } );\n\n    # Disable Bootstrap transitions to avoid timing issues.  Trying to\n    # click on an element whilst it animates fails with an \"Element ...\n    # could not be scrolled into view\" error.\n    $webdriver->js( '$.support.transition = false' );\n\n    push @failure, $self->_find_and_click([\n        '#selectall',\n        'button[data-target=\"#purge\"]',\n    ]);\n    $webdriver->find('button[type=\"submit\"][name=\"purge\"]')->click;\n\n    $test->ok( !@failure, $name );\n    $test->diag($_) foreach @failure;\n    $test->release;\n\n    return $self;\n}\n\n=head3 select_current_user_to_edit_ok\n\nFrom the I<< Manage users >> page, select the currently logged in user.\n\n\nsub select_current_user_to_edit_ok {\n    my ( $self, $name ) = @_;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok(\n        $name, $self->gads->username, 'user' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_field_to_edit_ok\n\nFrom the I<< Manage fields >> page, select a named field to edit.\n\n\nsub select_field_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'field' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_group_to_edit_ok\n\nFrom the I<< Groups >> page, select a named group to edit.\n\n\nsub select_group_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'group' );\n\n    $test->release;\n    return $result;\n}\n\n=head3 select_table_to_edit_ok\n\nFrom the I<< Manage tables >> page, select a named table to edit.\n\n\nsub select_table_to_edit_ok {\n    my $self = shift;\n    my $test = context();\n\n    my $result = $self->_select_item_row_to_edit_ok( @_, 'table' );\n    my $edit_el = $self->gads->webdriver->find(\n        '//*[contains( @class, \"list--tabs\")]//a[contains( ., \"Edit table\")]',\n        method => 'xpath',\n        dies => 0,\n    );\n    $result &&= $edit_el;\n    $edit_el->click if $edit_el;\n\n    $test->release;\n    return $result;\n}\n\nsub _select_item_row_to_edit_ok {\n    my ( $self, $name, $item_row_name, $type_name ) = @_;\n    $name //= \"Select the '${item_row_name}' ${type_name} to edit\";\n    my $test = context();\n\n    my $item_el = $self->_find_named_item_row_el($item_row_name);\n    my $success = $self->_check_only_one(\n        $item_el, \"${type_name} named '${item_row_name}'\" );\n\n    my $a_el = $item_el->find( 'a', dies => 0 );\n    if ( $a_el->size ) { $item_el = $a_el }\n\n    $item_el->click if $success;\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 select_record_to_view_ok\n\nFrom the I<< See records >> page, select a named record to view.\n\n\nsub select_record_to_view_ok {\n    my ( $self, $name, $record_name ) = @_;\n    $name //= \"Select the '${record_name}' record to view\";\n    my $test = context();\n\n    my $webdriver = $self->gads->webdriver;\n    my $xpath = \"//tr[ contains( ., '${record_name}') ]//td[1]//a[1]\";\n    my $link_el = $webdriver->find( $xpath, method => 'xpath', dies => 0 );\n    my $success = $self->_check_only_one(\n        $link_el, \"record named '${record_name}'\" );\n\n    $link_el->click if $success;\n    $test->ok( $success, $name );\n\n    $test->release;\n    return $self;\n}\n\n=head3 submit_add_a_field_form_ok\n\nSubmit the I<< Add a field >> form.  Takes a hash reference of arguments\nwhere C<< name >> contains the name of the new field to add, C<< type >>\nthe name of its type, and C<< group_name >> contains the name of an\nexisting group to assign all permissions to.\n\n\nsub submit_add_a_field_form_ok {\n    my ( $self, $name, $args_ref ) = @_;\n    $name //= 'Submit the add a field form';\n    my %arg = %$args_ref;\n\n    my $test = context();\n    my $webdriver = $self->gads->webdriver;\n\n    my $success = $self->_fill_in_field( 'input#name', $arg{name} );\n    my $type_el = $webdriver->find(\n        \"//*[ \\@id = 'type' ]/option[ text() = '$arg{type}' ]\",\n        method => 'xpath',\n    );\n    $success &&= $self->_check_only_one(\n        $type_el, \"type named '$arg{type}'\" );\n    $type_el->click if $success;\n\n    # Fill in checkboxes to give the specified group all permissions\n    my $permissions_tab_el = $webdriver->find('#permissions-tab')->click;\n    # Check the Permissions tab heading is shown\n    $webdriver->find(\n        '//h3[ contains( ., \"Permissions\" ) ]',\n        method => 'xpath',\n    );\n    # Click \"Add permissions\" button\n    $webdriver->find('#configure-permissions')->click;\n    # Select the desired group from the drop-down\n    my $group_option_el = $webdriver->find(\n        # TODO: \"contains\" isn't the same as \"equals\"\n        \"//select[ \\@id = 'select-permission-group' ]/option[ contains( ., '$arg{group_name}' ) ]\",\n        method => 'xpath',\n        dies => 0,\n    );\n    $success &&= $self->_check_only_one(\n        $group_option_el, \"group named '$arg{group_name}'\" );\n    if ($success) {\n        $group_option_el->click;\n        # Tick all \"access rights\" checkboxes, then submit the form\n        $_->click foreach $webdriver->find('.permission-rule input[name^=permission_]');\n        $webdriver->find('#add-permission-rule')->click;\n    }\n\n    $test->note(\"About to add a field named $arg{name}\");\n    $webdriver->find('#submit_save')->click;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 submit_add_a_group_form_ok\n\nSubmit the I<< Add a group >> form.\n\n\nsub submit_add_a_group_form_ok {\n    my ( $self, $name, $group_name ) = @_;\n    $name //= 'Submit the add a group form';\n\n    my $test = context();\n    my $success = $self->_fill_in_field( 'input[name=name]', $group_name );\n\n    $test->note(\"About to add a group named ${group_name}\");\n    $success &&= $self->_click_submit_button;\n\n    my $result = $test->ok( $success, $name );\n    $test->release;\n    return $result;\n}\n\n=head3 submit_add_a_table_form_ok\n\nSubmit the I<< Add a table >> form.  Takes similar arguments to L<<\n/submit_add_a_field_form_ok >> except for a table instead of a field."},"detail":"($self,$name,$args_ref)","kind":12,"range":{"end":{"character":9999,"line":1308},"start":{"line":1260,"character":0}},"line":1260,"name":"submit_add_a_table_form_ok","children":[{"line":1261,"name":"$self","containerName":"submit_add_a_table_form_ok","definition":"my","kind":13,"localvar":"my"},{"containerName":"submit_add_a_table_form_ok","kind":13,"line":1261,"name":"$name"},{"line":1261,"kind":13,"name":"$args_ref","containerName":"submit_add_a_table_form_ok"},{"containerName":"submit_add_a_table_form_ok","name":"$name","kind":13,"line":1262},{"localvar":"my","kind":13,"definition":"my","containerName":"submit_add_a_table_form_ok","name":"%arg","line":1263},{"name":"$args_ref","kind":13,"line":1263,"containerName":"submit_add_a_table_form_ok"},{"localvar":"my","kind":13,"containerName":"submit_add_a_table_form_ok","definition":"my","name":"$test","line":1265},{"name":"$success","line":1267,"containerName":"submit_add_a_table_form_ok","definition":"my","localvar":"my","kind":13},{"containerName":"submit_add_a_table_form_ok","name":"$self","kind":13,"line":1267},{"containerName":"submit_add_a_table_form_ok","line":1267,"kind":12,"name":"_fill_in_field"},{"line":1267,"kind":13,"name":"$arg","containerName":"submit_add_a_table_form_ok"},{"line":1269,"name":"$webdriver","kind":13,"localvar":"my","definition":"my","containerName":"submit_add_a_table_form_ok"},{"name":"$self","kind":13,"line":1269,"containerName":"submit_add_a_table_form_ok"},{"kind":12,"line":1269,"name":"gads","containerName":"submit_add_a_table_form_ok"},{"line":1269,"kind":12,"name":"webdriver","containerName":"submit_add_a_table_form_ok"},{"containerName":"submit_add_a_table_fo